import{_ as o,M as a,p as t,q as n,R as e,t as l,N as r,a1 as s}from"./framework-e0dd9823.js";const d={},c=e("h1",{id:"每周一词-live",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#每周一词-live","aria-hidden":"true"},"#"),l(" 每周一词-Live")],-1),h=e("p",null,"2023 年 5 月 2 日 17:55:49",-1),v={href:"https://www.bbc.co.uk/learningenglish/chinese/features/english-in-a-minute/ep-230414",target:"_blank",rel:"noopener noreferrer"},u=s('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>Live” 是我们初学英语时就常见到的单词，它看似简单，用法却不少。我们可以用动词 “live” 表示 “生存”、“居住” 或 “尽情享受生活”，用动词短语 “live off” 或 “live on” 表示 “靠...过活”，用 “live for” 表示 “为...而活”。听主持人 Phil 总结单词 “live” 的常见用法。</p><h2 id="用法总结" tabindex="-1"><a class="header-anchor" href="#用法总结" aria-hidden="true">#</a> 用法总结</h2><ol><li>“Live”最基础的含义是“活着、生存”。</li></ol><ul><li>Humans need water to live.</li></ul><ol start="2"><li>动词“live”可以表示“居住，住在（某地）”。</li></ol><ul><li>I live in Xi&#39;an.</li><li>They&#39;ve lived in this house for decades.</li></ul><ol start="3"><li>动词短语“live off”或“live on”可以表示“靠...生活”。</li></ol><ul><li>That salary is not enough to live off!</li><li>I can&#39;t cook, so I live on ready meals.</li></ul><ol start="4"><li>动词短语“live for”用来表示“为...而活”。</li></ol><ul><li>I live for family.</li><li>I live for the weekend; I love to party!</li></ul><ol start="5"><li>动词“live”还可以表达“尽情地享受充实的生活”。</li></ol><ul><li>I need to live, not just work every day in a boring job.</li><li>To me, living is eating all kinds of delicious food.</li></ul>',13);function f(_,p){const i=a("ExternalLinkIcon");return t(),n("div",null,[c,h,e("p",null,[e("a",v,[l("BBC"),r(i)])]),u])}const k=o(d,[["render",f],["__file","word-live.html.vue"]]);export{k as default};
